import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Select } from 'antd';
import RarityTable from '../RarityTable';
import CollabitsImageProvider from './ImageProvider';

const CollabitsSearch = props => {
  const [multiSelections, setMultiSelections] = useState([]);
  // eslint-disable-next-line no-unused-vars
  const [contentTags, setContentTags] = useState([]);
  const [optionTags, setOptionTags] = useState([]);
  const [searchResult, setSearchResult] = useState([]);

  const [modalSearchShow, setModalSearchShow] = useState(false);
  const [noMatchingWording, setNoMatchingWording] = useState();
  const [hasMore, setHasMore] = useState(true);

  // Fetch images on component mount
  useEffect(() => {
    getAllTags();
  }, []);

  const getOptionTags = tags => {
    if (tags) {
      const optionTagsResult = [];
      for (let i = 0; i < tags.length; i++)
        optionTagsResult.push({
          value: tags[i],
          key: 'tag-key-name' + tags[i],
        });
      setOptionTags(optionTagsResult);
    }
  };

  // Fetch images on component mount
  useEffect(() => {
    setNoMatchingWording(<p></p>);
    if (multiSelections.length === 0) {
      setSearchResult([]);
      setHasMore(true);
    } else {
      setSearchResult([]);
      setHasMore(false);
      getCBitsByNumbers();
    }
  }, [multiSelections]);

  // API endpoint
  const endpoint = 'https://backend.cardanobits.art:9364';
  // Fetch Images from functions
  const getAllTags = () => {
    axios(endpoint + '/collabits/tags').then(res => {
      getOptionTags(res.data);
    });
  };

  const getCBitsByNumbers = () => {
    const arrayOfTags = multiSelections.map(a => a);
    axios(endpoint + `/collabits/ids?ids=${arrayOfTags}`).then(res => {
      if (res.data.length === 0) {
        setSearchResult([]);
      } else {
        setSearchResult([...res.data]);
      }
    });
  };

  function handleChange(value) {
    setMultiSelections(value);
  }

  return (
    <>
      <section className="swag" id="collection">
        <div className="container text-center">
          <div className="row">
            <div className="col-md-12">
              <h1 className="arrow">
                Our <span>Collection</span>
              </h1>
              <p>
                Only 10.000 CardanoBits were minted, using a{' '}
                <a href="https://cardanoscan.io/tokenPolicy/1131301ad4b3cb7deaddbc8f03f77189082a5738c0167e1772233097">
                  time-locked policy
                </a>
                . Each one is unique, and generated with a mix of art pieces and
                computer algorithms. Check the{' '}
                <a href="#collection" onClick={() => setModalSearchShow(true)}>
                  tags/types
                </a>{' '}
                table!
              </p>
              <RarityTable
                tags={contentTags}
                show={modalSearchShow}
                onHide={() => setModalSearchShow(false)}
              />
            </div>
          </div>
          <div className="row">
            <div className="col-md-12">
              <br />
              <Select
                className="search-bar"
                mode="multiple"
                placeholder="Search by number or tags!"
                onChange={handleChange}
                options={optionTags}
              />
              <br />
              <br />
            </div>
          </div>

          <div className="row ">
            <br />
            <div className="col-md-12">
              <CollabitsImageProvider
                searchResult={searchResult}
                multiSelections={multiSelections}
                hasMore={hasMore}
              />
              {noMatchingWording}
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default CollabitsSearch;
